"use client";

import Link from 'next/link';
import { ShoppingBag, Search, User, Heart, Truck, Menu, Home, X } from 'lucide-react';
import styles from './Header.module.css';
import { useState } from 'react';

export default function Header() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <>
      <div className={styles.headerWrapper}>
        <div className={styles.topBar}>
          SPEND $59 TO UNLOCK FREE SHIPPING FOR U.S.A ORDERS <Link href="/shop" style={{ textDecoration: 'underline', marginLeft: '5px' }}>SHOP NOW</Link>
        </div>

        <div className={`container ${styles.mainHeader}`}>
          <div
            className={styles.mobileMenuTrigger}
            style={{ display: 'none', position: 'absolute', left: '20px', cursor: 'pointer' }}
            onClick={toggleMenu}
          >
            <Menu size={24} />
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '2rem' }}>
            <Link href="/" className={styles.logo}>
              <span style={{ fontFamily: 'serif', fontSize: '2.2rem', fontWeight: 'bold' }}>JerseyPerfume</span>
            </Link>
          </div>

          <div className={styles.searchContainer}>
            <Search className={styles.searchIcon} size={18} />
            <input type="text" placeholder="Search for products or brands" className={styles.searchInput} />
          </div>

          <div className={styles.headerActions}>
            <Link href="/wishlist" className={styles.iconBtn}>
              <Heart size={24} strokeWidth={1.5} />
            </Link>
            <Link href="/account" className={styles.iconBtn}>
              <User size={24} strokeWidth={1.5} />
            </Link>
            <Link href="/cart" className={styles.iconBtn}>
              <ShoppingBag size={24} strokeWidth={1.5} />
            </Link>
          </div>
        </div>

        <div className="container" style={{ borderTop: '1px solid #f0f0f0' }}>
          <div className={styles.navBar}>
            <nav className={styles.navLinks}>
              <Link href="/new-arrivals" className={styles.navLink} style={{ color: '#D32F4D' }}>JerseyPerfume</Link>
              <Link href="/new-arrivals" className={styles.navLink}>New Arrivals</Link>
              <Link href="/gifts" className={styles.navLink}>Gifts +</Link>
              <Link href="/womens" className={styles.navLink}>Women's Fragrances +</Link>
              <Link href="/mens" className={styles.navLink}>Men's Fragrances +</Link>
              <Link href="/brands" className={styles.navLink}>Brands +</Link>
              <Link href="/gift-sets" className={styles.navLink}>Gift Sets +</Link>
              <Link href="/bundles" className={styles.navLink}>Bundles</Link>
            </nav>
            <div className={styles.trackOrder}>
              <Truck size={16} /> Track Order
            </div>
          </div>
        </div>
      </div>

      {/* Mobile Menu Sidebar */}
      <div className={`${styles.mobileMenu} ${isMenuOpen ? styles.open : ''}`}>
        <div className={styles.mobileMenuContent}>
          <div className={styles.closeBtn} onClick={toggleMenu}>
            <X size={24} />
          </div>
          <Link href="/new-arrivals" className={styles.mobileNavLink} onClick={toggleMenu} style={{ color: '#D32F4D' }}>JerseyPerfume</Link>
          <Link href="/new-arrivals" className={styles.mobileNavLink} onClick={toggleMenu}>New Arrivals</Link>
          <Link href="/gifts" className={styles.mobileNavLink} onClick={toggleMenu}>Gifts +</Link>
          <Link href="/womens" className={styles.mobileNavLink} onClick={toggleMenu}>Women's Fragrances +</Link>
          <Link href="/mens" className={styles.mobileNavLink} onClick={toggleMenu}>Men's Fragrances +</Link>
          <Link href="/brands" className={styles.mobileNavLink} onClick={toggleMenu}>Brands +</Link>
          <Link href="/gift-sets" className={styles.mobileNavLink} onClick={toggleMenu}>Gift Sets +</Link>
          <Link href="/bundles" className={styles.mobileNavLink} onClick={toggleMenu}>Bundles</Link>
        </div>
      </div>

      {/* Mobile Bottom Navigation */}
      <div className={styles.mobileBottomNav}>
        <Link href="/" className={styles.mobileNavItem}>
          <Home size={22} strokeWidth={1.5} />
          <span>Home</span>
        </Link>
        <Link href="/shop" className={styles.mobileNavItem}>
          <Search size={22} strokeWidth={1.5} />
          <span>Shop</span>
        </Link>
        <Link href="/wishlist" className={styles.mobileNavItem}>
          <Heart size={22} strokeWidth={1.5} />
          <span>Wishlist</span>
        </Link>
        <Link href="/account" className={styles.mobileNavItem}>
          <User size={22} strokeWidth={1.5} />
          <span>Account</span>
        </Link>
        <Link href="/cart" className={styles.mobileNavItem}>
          <ShoppingBag size={22} strokeWidth={1.5} />
          <span>Cart</span>
        </Link>
      </div>
    </>
  );
}
